def safe_int(campo: str, valor: str):
    texto = valor.strip()
    if texto == "":
        return (False, None, f"ERROR en {campo!r}: vacío (raw={valor!r})")
    try:
        n = int(texto)
        return (True, n, None)
    except ValueError:
        return (False, None, f"ERROR en {campo!r}: no es entero (raw={valor!r})")

for v in [" 21 ", "", "abc", "  "]:
    print(repr(v), "→", safe_int("edad", v))

